var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"라이트닝! 익스큐션───!","JPN":"ライトニング！　エクスキュージョン───！","ENG":"Lightning! Execution ──!","TWN":"雷光！處刑───！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_NULL","text":{"KOREA":"호오, 버러지 같은 필멸자 주제에 제법 발버둥 치는구나.","JPN":"ほう、虫けら同然の定命の者にしては随分と耐えるな。","ENG":"Oh? Struggling quite a bit for a lowly mortal, aren't you?","TWN":"喔，像蟲子一樣的凡人，居然還掙扎得挺厲害的嘛。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_NULL","text":{"KOREA":"하지만 그 또한 부질없는 발악일지니.","JPN":"しかしそれもまた、無駄な足掻きにすぎん。","ENG":"But it's all just meaningless resistance.","TWN":"但那也不過是徒勞的掙扎罷了。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_NULL","text":{"KOREA":"일어나거라, 왕의 자매들이여!","JPN":"立ち上がるのだ、王の姉妹たちよ！","ENG":"Get up, sisters of the Queen!","TWN":"起來吧，王的姊妹們！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"크윽! 역시 그림자를 부리는 능력이 성가시군!","JPN":"くっ！　やはりシャドウを操る能力が厄介だな！","ENG":"Tch... Controlling Shadows really is a damn nuisance!","TWN":"呃！果然操縱暗影的能力很棘手！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"망설일 시간이 없어… 거리를 좁히지 않으면 이쪽이 불리해……!","JPN":"迷っている場合じゃない……距離を縮めなければ、こっちが不利だ……！","ENG":"No time to hesitate... If we don't close the distance, we're at a serious disadvantage...!","TWN":"沒有時間猶豫了……如果不拉近距離，我們這邊會很不利……！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COMPANY_MAIN_NPC_CAP","text":{"KOREA":"전 대원! 사도의 그림자를 집중 타격한다!","JPN":"総員！　使徒のシャドウに攻撃を集中しろ！","ENG":"All units, focus fire on the Apostle's Shadows!","TWN":"全體隊員！集中攻擊使徒的暗影！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"COMPANY_MAIN_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"COMPANY_MAIN_NPC_CAP","text":{"KOREA":"대령님께서 사도에게 가까이 접근할 수 있도록, 전력으로 지원하는 거다!","JPN":"大佐が使徒に近づけるよう、全力でサポートするんだ！","ENG":"Give the Colonel everything you've got and clear a path to the Apostle!","TWN":"全力支援，讓大人能夠接近使徒！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"COMPANY_MAIN_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"좋아, 지금이에요! 아키! 제가 길을 열게요!","JPN":"よし、今です、秋！　道を開けますね！","ENG":"Now's our chance! Aki! I'll clear the path!","TWN":"好了，就是現在！廣瀨秋！我來開路！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"하아아아아아아앗…!! 버스터……!!","JPN":"はあああああああ……！！　バスター……！！","ENG":"Haaaaaah! Buster!","TWN":"哈啊啊啊啊啊啊啊……！！破壞者……！！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_NULL","text":{"KOREA":"불경하구나, 필멸자여.","JPN":"不敬なり、定命の者よ。","ENG":"Insolent mortal.","TWN":"這是不敬，必滅者。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_NULL","text":{"KOREA":"그런 허술한 공격이 이 몸에게 닿을 것 같으냐!","JPN":"そのような拙い攻撃が、余に届くはずがなかろう！","ENG":"You think such a feeble strike could reach me?","TWN":"這種拙劣的攻擊能打到我嗎！"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"그래? 그럼, 이건 어때……!?","JPN":"そう？　じゃあ、これはどう……！？","ENG":"Oh yeah? Then how about this...?","TWN":"是嗎？那這個呢……！"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_NULL","text":{"KOREA":"후후, 기습을 노리고 있다는 건 알고 있었다.","JPN":"ふふ、奇襲を狙っていたのは知っていた。","ENG":"Haha, I knew you were aiming for an ambush.","TWN":"呵呵，我早就知道你在伺機偷襲。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_NULL","text":{"KOREA":"하지만 이미 말하지 않았느냐? 전부 부질없는 발악이라고.","JPN":"しかし言ったであろう。全ては無駄な足掻きだと。","ENG":"But haven't I told you already? It's all just meaningless resistance.","TWN":"但是我不是已經說過了嗎？這一切都是徒勞的掙扎。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_NULL","text":{"KOREA":"이 몸과 정면으로 검을 맞부딪친 시점에서 네놈의 패배이니라.","JPN":"余と正面から剣を交えた時点で、貴様の負けだ。","ENG":"The moment you crossed blades with me head-on, your defeat was sealed.","TWN":"從你正面迎上我的劍的那一刻起，你就已經輸了。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"크윽…! 칼 싸움 같은 건 아무래도 좋거든……!","JPN":"くっ……！　剣の腕なんてどうでもいい……！","ENG":"Ugh...! I couldn't care less about swordfights...!","TWN":"呃……！刀劍之爭什麼的無所謂……！"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"어차피 내 전력은 가불기니까……!","JPN":"どうせ秋の全力はガード不能だもの……！","ENG":"You can't maintain guard against my attacks anyways...!","TWN":"反正我的全力攻擊是無法防禦的……！"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_NULL","text":{"KOREA":"읏…? 검의 무게가……!?","JPN":"なっ……？　剣が……重くなっ……！？","ENG":"Ugh...? Why is your sword so heavy...?","TWN":"呃……？劍的重量……？！"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"필살! 중량검 5000배!","JPN":"必殺！　重量剣5000倍！","ENG":"Here comes a fatal blow! Ultra Heavy Sword 5000x!","TWN":"必殺！重劍5000倍！"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"하아아아아아아아아아……!","JPN":"はあああああああああ……！","ENG":"Haaaaaaaaah...!","TWN":"哈啊啊啊啊啊啊啊啊……！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_WAVE","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};